#include <stdlib.h>
typedef struct Node Node;
struct Node { size_t weight; Node *tail; int count; };
typedef struct NodePool { Node *next; } NodePool;

static void probe(Node *(*lists)[2], Node *leaves, int numsymbols, NodePool *pool, int index)
__CPROVER_requires(index == 1)
__CPROVER_requires(numsymbols >= 1 && numsymbols <= 8)
__CPROVER_requires(__CPROVER_is_fresh(lists, (size_t)(index + 1) * sizeof(*lists)))
__CPROVER_requires(__CPROVER_is_fresh(lists[index][1], sizeof(Node)))
__CPROVER_requires(__CPROVER_is_fresh(lists[index - 1][0], sizeof(Node)))
__CPROVER_requires(__CPROVER_is_fresh(lists[index - 1][1], sizeof(Node)))
__CPROVER_requires(__CPROVER_is_fresh(pool, sizeof(*pool)) && __CPROVER_is_fresh(pool->next, sizeof(Node)))
__CPROVER_requires(__CPROVER_is_fresh(leaves, (size_t)(numsymbols + 2) * sizeof(*leaves)))
__CPROVER_requires(lists[index][1]->count >= 0 && lists[index][1]->count <= numsymbols + 1)
__CPROVER_ensures(1 == 0)
{
    int lastcount = lists[index][1]->count;
    size_t sum = lists[index - 1][0]->weight + lists[index - 1][1]->weight;
    if (lastcount < numsymbols && sum > leaves[lastcount].weight) {
        Node *nc = pool->next; Node *oc = lists[index][1]->tail;
        lists[index][1] = nc; nc->count = lastcount + 1; nc->tail = oc;
    } else { lists[index][1]->tail = lists[index - 1][1]; }
}
EOF
