"f01":"__CPROVER_requires(__CPROVER_is_fresh(lists[index - 1][1], sizeof(Node)))",
"pool":"__CPROVER_requires(__CPROVER_is_fresh(pool, sizeof(*pool)) && __CPROVER_is_fresh(pool->next, sizeof(Node)))",
"lv":"__CPROVER_requires(__CPROVER_is_fresh(leaves, (size_t)(numsymbols + 2) * sizeof(*leaves)))",
"cnt":"__CPROVER_requires(lists[index][1]->count >= 0 && lists[index][1]->count <= numsymbols + 1)",
}
body='''{
    int lastcount = lists[index][1]->count;
    size_t sum = lists[index - 1][0]->weight + lists[index - 1][1]->weight;
    if (lastcount < numsymbols && sum > leaves[lastcount].weight) {
        Node *nc = pool->next; Node *oc = lists[index][1]->tail;
        lists[index][1] = nc; nc->count = lastcount + 1; nc->tail = oc;
    } else { lists[index][1]->tail = lists[index - 1][1]; }
}'''
def test(keys, label):
    c=hdr+"\n".join(reqs[k] for k in keys)+"\n__CPROVER_ensures(1 == 0)\n"+body
    open("t.c","w").write(c)
    subprocess.run(["goto-cc","-o","t.goto","t.c","--function","probe"],capture_output=True)
    subprocess.run(["goto-instrument","--partial-loops","--unwind","5","t.goto","t.goto"],capture_output=True)
    subprocess.run(["goto-instrument","--enforce-contract","probe","t.goto","tchk.goto"],capture_output=True)
    r=subprocess.run(["cbmc","tchk.goto","--function","probe","--depth","200"],capture_output=True,text=True)
    out=r.stdout+r.stderr
    v="VACUOUS" if "VERIFICATION SUCCESSFUL" in out else "non-vac"
    print(f"{label}: {v}")
allk=list(reqs.keys())
test(allk,"ALL")
for drop in ["cnt","lv","pool","f00","f01","f11","ns"]:
    test([k for k in allk if k!=drop], f"drop {drop}")
